import SwiftUI
import Combine

// MARK: - Models

enum TradeType: String, Codable, CaseIterable {
    case buy, sell
}

struct Trade: Identifiable, Codable {
    let id: UUID
    let symbol: String
    let amount: Double
    let price: Double
    let type: TradeType
    let timestamp: Date

    init(symbol: String, amount: Double, price: Double, type: TradeType) {
        self.id = UUID()
        self.symbol = symbol
        self.amount = amount
        self.price = price
        self.type = type
        self.timestamp = Date()
    }
}

struct PortfolioPosition: Identifiable, Codable {
    let id = UUID()
    let symbol: String
    var quantity: Double
    var averagePrice: Double
}

// MARK: - Certificate Pinning Delegate for Secure API Communication

class PinningURLSessionDelegate: NSObject, URLSessionDelegate {
    let validCertificateData: Data

    init(validCertificateData: Data) {
        self.validCertificateData = validCertificateData
    }

    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        if
            let serverTrust = challenge.protectionSpace.serverTrust,
            let certificate = SecTrustGetCertificateAtIndex(serverTrust, 0) {
            let remoteCertificateData = SecCertificateCopyData(certificate) as Data

            if remoteCertificateData == validCertificateData {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
                return
            }
        }
        completionHandler(.cancelAuthenticationChallenge, nil)
    }
}

// MARK: - API Client

class APIClient {
    private let session: URLSession

    init() {
        // Replace "certificate_placeholder" with your valid certificate data.
        let certificateData = Data(base64Encoded: "certificate_placeholder") ?? Data()
        let delegate = PinningURLSessionDelegate(validCertificateData: certificateData)
        session = URLSession(configuration: .default, delegate: delegate, delegateQueue: nil)
    }

    func executeTrade(trade: Trade, completion: @escaping (Result<Trade, Error>) -> Void) {
        guard let url = URL(string: "https://api.yourtradingplatform.com/trade") else {
            completion(.failure(URLError(.badURL)))
            return
        }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        // Assuming token-based authentication; replace with actual token retrieval logic.
        request.addValue("Bearer YOUR_AUTH_TOKEN", forHTTPHeaderField: "Authorization")
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")

        do {
            let body = try JSONEncoder().encode(trade)
            request.httpBody = body
        } catch {
            completion(.failure(error))
            return
        }

        session.dataTask(with: request) { data, response, error in
            if let error = error {
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            }
            guard let data = data else {
                DispatchQueue.main.async { completion(.failure(URLError(.badServerResponse))) }
                return
            }
            do {
                let returnedTrade = try JSONDecoder().decode(Trade.self, from: data)
                DispatchQueue.main.async { completion(.success(returnedTrade)) }
            } catch {
                DispatchQueue.main.async { completion(.failure(error)) }
            }
        }.resume()
    }
}

// MARK: - Trade Manager

class TradeManager: ObservableObject {
    @Published var recentTrades: [Trade] = []
    private let apiClient = APIClient()
    private let portfolioManager: PortfolioManager

    init(portfolioManager: PortfolioManager) {
        self.portfolioManager = portfolioManager
    }

    func submitTrade(symbol: String, amount: Double, price: Double, type: TradeType) {
        let newTrade = Trade(symbol: symbol, amount: amount, price: price, type: type)
        apiClient.executeTrade(trade: newTrade) { [weak self] result in
            switch result {
            case .success(let executedTrade):
                self?.recentTrades.insert(executedTrade, at: 0)
                self?.portfolioManager.updatePortfolio(with: executedTrade)
            case .failure(let error):
                print("Trade failed: \(error)")
            }
        }
    }
}

// MARK: - Portfolio Manager

class PortfolioManager: ObservableObject {
    @Published var positions: [PortfolioPosition] = []

    func updatePortfolio(with trade: Trade) {
        if let index = positions.firstIndex(where: { $0.symbol == trade.symbol }) {
            var position = positions[index]
            if trade.type == .buy {
                let totalCost = position.averagePrice * position.quantity + trade.price * trade.amount
                position.quantity += trade.amount
                position.averagePrice = totalCost / position.quantity
            } else {
                position.quantity -= trade.amount
                if position.quantity <= 0 {
                    positions.remove(at: index)
                    return
                }
            }
            positions[index] = position
        } else {
            if trade.type == .buy {
                let position = PortfolioPosition(symbol: trade.symbol, quantity: trade.amount, averagePrice: trade.price)
                positions.append(position)
            }
        }
    }
}

// MARK: - SwiftUI Views

struct TradeView: View {
    @ObservedObject var tradeManager: TradeManager

    @State private var symbol: String = ""
    @State private var amount: String = ""
    @State private var price: String = ""
    @State private var selectedTradeType: TradeType = .buy

    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
                Form {
                    Section(header: Text("New Trade")) {
                        TextField("Symbol", text: $symbol)
                        TextField("Amount", text: $amount)
                            .keyboardType(.decimalPad)
                        TextField("Price", text: $price)
                            .keyboardType(.decimalPad)
                        Picker("Type", selection: $selectedTradeType) {
                            ForEach(TradeType.allCases, id: \.self) { type in
                                Text(type.rawValue.capitalized)
                            }
                        }.pickerStyle(SegmentedPickerStyle())
                    }
                }
                Button(action: submitTrade) {
                    Text("Execute Trade")
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(Color.blue)
                        .foregroundColor(.white)
                        .cornerRadius(8)
                }.padding()

                List(tradeManager.recentTrades) { trade in
                    VStack(alignment: .leading) {
                        Text("\(trade.type.rawValue.capitalized) \(trade.symbol)")
                            .font(.headline)
                        Text("Amount: \(trade.amount, specifier: "%.2f") @ \(trade.price, specifier: "%.2f")")
                            .font(.subheadline)
                        Text("Executed: \(trade.timestamp, formatter: dateFormatter)")
                            .font(.caption)
                    }
                }
            }
            .navigationTitle("Trade Execution")
        }
    }

    private func submitTrade() {
        guard let amt = Double(amount), let prc = Double(price), !symbol.isEmpty else { return }
        tradeManager.submitTrade(symbol: symbol.uppercased(), amount: amt, price: prc, type: selectedTradeType)
        symbol = ""
        amount = ""
        price = ""
    }

    private var dateFormatter: DateFormatter {
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .short
        return formatter
    }
}

